#define _GNU_SOURCE
#include <stdio.h>
#include <unistd.h>
#include <fcntl.h>
#include <string.h>
#include <stdlib.h>

/* == EXEMPLE =======================================
 * splice() entre 2 pipes : zero-copy pipe-to-pipe
 * ================================================= */
void example_splice_pipes(void) {
    int p1[2], p2[2];
    pipe(p1); pipe(p2);
    write(p1[1], "hello", 5);
    close(p1[1]);
    splice(p1[0], NULL, p2[1], NULL, 5, 0);
    close(p2[1]);
    char buf[16];
    ssize_t n = read(p2[0], buf, sizeof(buf)-1);
    buf[n] = '\0';
    printf("Pipe-to-pipe: %s\n", buf);
    close(p1[0]); close(p2[0]);
}
/* Resultat: Pipe-to-pipe: hello */

